     1→// Audio preprocessing: raw PCM (signed 16-bit LE) -> mono f32 at 16 kHz.
     2→// Ready for whisper-rs consumption.
     3→// Accepts any input sample rate (e.g. 48 kHz built-in, 16 kHz Bluetooth HFP).
     4→
     5→use crate::PabloError;
     6→use byteorder::{LittleEndian, ReadBytesExt};
     7→use rubato::{
     8→    Resampler, SincFixedIn, SincInterpolationParameters, SincInterpolationType, WindowFunction,
     9→};
    10→use std::io::Cursor;
    11→
    12→const TARGET_SAMPLE_RATE: u32 = 16000;
    13→
    14→fn audio_err(msg: String) -> PabloError {
    15→    PabloError::AudioPreprocessing { message: msg }
    16→}
    17→
    18→/// Read a raw PCM sidecar file (signed 16-bit LE, no header),
    19→/// downmix to mono if stereo, resample to 16 kHz, and return normalized f32 samples.
    20→///
    21→/// - `path`: absolute path to the raw PCM file
    22→/// - `channels`: 1 (mono mic) or 2 (stereo interleaved system audio)
    23→/// - `sample_rate`: actual sample rate of the input (e.g. 48000, 44100, 16000)
    24→pub async fn preprocess_pcm(
    25→    path: String,
    26→    channels: u8,
    27→    sample_rate: u32,
    28→) -> Result<Vec<f32>, PabloError> {
    29→    if channels == 0 || channels > 2 {
    30→        return Err(audio_err(format!(
    31→            "unsupported channel count: {channels} (expected 1 or 2)"
    32→        )));
    33→    }
    34→    if sample_rate == 0 {
    35→        return Err(audio_err("sample_rate must be > 0".to_string()));
    36→    }
    37→
    38→    // Read the raw PCM file
    39→    let raw_bytes = tokio::fs::read(&path)
    40→        .await
    41→        .map_err(|e| audio_err(format!("failed to read PCM file '{path}': {e}")))?;
    42→
    43→    if raw_bytes.is_empty() {
    44→        return Ok(Vec::new());
    45→    }
    46→
    47→    // Each sample is 2 bytes (signed 16-bit LE)
    48→    let total_samples = raw_bytes.len() / 2;
    49→    if raw_bytes.len() % 2 != 0 {
    50→        return Err(audio_err(
    51→            "PCM file has odd byte count; expected 16-bit (2 bytes per sample)".to_string(),
    52→        ));
    53→    }
    54→
    55→    // Parse i16 samples
    56→    let mut cursor = Cursor::new(&raw_bytes);
    57→    let mut samples_i16 = Vec::with_capacity(total_samples);
    58→    for _ in 0..total_samples {
    59→        let sample = cursor
    60→            .read_i16::<LittleEndian>()
    61→            .map_err(|e| audio_err(format!("failed to read PCM sample: {e}")))?;
    62→        samples_i16.push(sample);
    63→    }
    64→
    65→    // Convert to f32 normalized [-1.0, 1.0] and downmix to mono if stereo
    66→    let mono_f32: Vec<f32> = if channels == 2 {
    67→        if samples_i16.len() % 2 != 0 {
    68→            return Err(audio_err(
    69→                "stereo PCM has odd sample count; expected interleaved L/R pairs".to_string(),
    70→            ));
    71→        }
    72→        samples_i16
    73→            .chunks_exact(2)
    74→            .map(|pair| {
    75→                let left = pair[0] as f32 / 32768.0;
    76→                let right = pair[1] as f32 / 32768.0;
    77→                (left + right) / 2.0
    78→            })
    79→            .collect()
    80→    } else {
    81→        samples_i16
    82→            .iter()
    83→            .map(|&s| s as f32 / 32768.0)
    84→            .collect()
    85→    };
    86→
    87→    if mono_f32.is_empty() {
    88→        return Ok(Vec::new());
    89→    }
    90→
    91→    // Skip resampling if already at target rate
    92→    if sample_rate == TARGET_SAMPLE_RATE {
    93→        return Ok(mono_f32);
    94→    }
    95→
    96→    resample_to_16k(mono_f32, sample_rate)
    97→}
