    99→/// Resample mono f32 audio from `input_rate` Hz to 16 kHz using rubato's SincFixedIn.
   100→fn resample_to_16k(input: Vec<f32>, input_rate: u32) -> Result<Vec<f32>, PabloError> {
   101→    let ratio = TARGET_SAMPLE_RATE as f64 / input_rate as f64;
   102→
   103→    let params = SincInterpolationParameters {
   104→        sinc_len: 256,
   105→        f_cutoff: 0.95,
   106→        interpolation: SincInterpolationType::Linear,
   107→        oversampling_factor: 256,
   108→        window: WindowFunction::BlackmanHarris2,
   109→    };
   110→
   111→    let chunk_size = 1024;
   112→    let mut resampler = SincFixedIn::<f32>::new(
   113→        ratio,
   114→        2.0,
   115→        params,
   116→        chunk_size,
   117→        1, // mono
   118→    )
   119→    .map_err(|e| audio_err(format!("resampler init failed: {e}")))?;
   120→
   121→    let estimated_output = (input.len() as f64 * ratio).ceil() as usize + 1024;
   122→    let mut output = Vec::with_capacity(estimated_output);
   123→
   124→    // Process full chunks
   125→    let mut pos = 0;
   126→    while pos + chunk_size <= input.len() {
   127→        let chunk = vec![input[pos..pos + chunk_size].to_vec()];
   128→        let resampled = resampler
   129→            .process(&chunk, None)
   130→            .map_err(|e| audio_err(format!("resample failed: {e}")))?;
   131→        if !resampled.is_empty() {
   132→            output.extend_from_slice(&resampled[0]);
   133→        }
   134→        pos += chunk_size;
   135→    }
   136→
   137→    // Process remaining samples (pad with zeros to fill the last chunk)
   138→    if pos < input.len() {
   139→        let remaining = &input[pos..];
   140→        let mut padded = remaining.to_vec();
   141→        padded.resize(chunk_size, 0.0);
   142→        let chunk = vec![padded];
   143→        let resampled = resampler
   144→            .process(&chunk, None)
   145→            .map_err(|e| audio_err(format!("resample tail failed: {e}")))?;
   146→        if !resampled.is_empty() {
   147→            // Only keep the proportional number of output samples for the real data
   148→            let expected_out = (remaining.len() as f64 * ratio).ceil() as usize;
   149→            let out_samples = &resampled[0];
   150→            let take = expected_out.min(out_samples.len());
   151→            output.extend_from_slice(&out_samples[..take]);
   152→        }
   153→    }
   154→
   155→    Ok(output)
   156→}
